#define X first
#define Y second
#define MP make_pair

using namespace std;

const int N = 3e5 + 123;
const ll mod = 1e9 + 7;

int n, h, w;
pair<int, int> a[N];
ll f[N];
ll dp[N];

ll bin_pow(ll x, ll y) {
    ll res = 1;
    x %= mod;
    while (y > 0) {
        if (y & 1) res = (res * x) % mod;
        x = (x * x) % mod;
        y >>= 1;
    }
    return res;
}

ll calc(ll x, ll y) {
    if (x < 0 || y < 0) return 0;
    return f[x + y - 2] * bin_pow(f[x - 1], mod - 2) % mod * bin_pow(f[y - 1], mod - 2) % mod;
}

