        f[i] = (f[i - 1] * i) % mod;
    }

    cin >> h >> w >> n;
    for (int i = 1; i <= n; ++i) {
        int x, y;
        cin >> x >> y;
        a[i] = MP(x, y);
    }
    a[++n] = MP(h, w);

    sort(a + 1, a + n + 1);

    dp[n] = 1;
    for (int i = n - 1; i >= 1; --i) {
        ll all = calc(a[i].X, a[i].Y);
        for (int j = i + 1; j <= n; ++j) {
            all = (all - (dp[j] * calc(a[i].X - a[j].X + 1, a[i].Y - a[j].Y + 1) % mod) + mod) % mod;
        }
        dp[i] = all;
    }

    cout << dp[1] << endl;

    return 0;
}

